1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	
7	const COMPONENT_BASE_PREMIUM = 25;
8	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
9	const COMPONENT_BLOCK_SIZE = 3;
10	const COMPONENT_BLOCK_PREMIUM = 60;
11	
12	const NON_COMPONENT_BASE_PREMIUM: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	};
18	
19	const isComponent = (type: string): boolean => COMPONENT_TYPES.has(type);
20	
21	const basePremiumFor = (type: string): number =>
22	  isComponent(type) ? COMPONENT_BASE_PREMIUM : NON_COMPONENT_BASE_PREMIUM[type];
23	
24	type Item = { type: string; cursed?: boolean; enchantment?: number };
25	type QuoteStep = { op: "quote"; items: Item[] };
26	type Step = QuoteStep;
27	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
28	
29	const groupedBasePremium = (type: string, count: number): number => {
30	  if (isComponent(type) && count === COMPONENT_BLOCK_SIZE) {
31	    return COMPONENT_BLOCK_PREMIUM;
32	  }
33	  return count * basePremiumFor(type);
34	};
35	
36	const countByType = (items: Item[]): Map<string, number> => {
37	  const counts = new Map<string, number>();
38	  for (const item of items) {
39	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
40	  }
41	  return counts;
42	};
43	
44	const sumBasePremiums = (items: Item[]): number =>
45	  Array.from(countByType(items)).reduce(
46	    (total, [type, count]) => total + groupedBasePremium(type, count),
47	    0,
48	  );
49	
50	const curseSurchargeFor = (item: Item): number =>
51	  item.cursed ? basePremiumFor(item.type) * CURSE_SURCHARGE_RATE : 0;
52	
53	const highEnchantmentSurchargeFor = (item: Item): number =>
54	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
55	    ? basePremiumFor(item.type) * HIGH_ENCHANTMENT_SURCHARGE_RATE
56	    : 0;
57	
58	const sumItemSurcharges = (items: Item[]): number =>
59	  items.reduce(
60	    (sum, item) =>
61	      sum + curseSurchargeFor(item) + highEnchantmentSurchargeFor(item),
62	    0,
63	  );
64	
65	const quotePremium = (items: Item[]): number => {
66	  const basePremium = sumBasePremiums(items);
67	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
68	  const insurancePremium = Math.ceil(
69	    basePremium + sumItemSurcharges(items) + firstInsuranceSurcharge,
70	  );
71	  return insurancePremium + PROCESSING_FEE;
72	};
73	
74	const runStep = (step: Step) => ({ premium: quotePremium(step.items) });
75	
76	export const runScenario = (scenario: Scenario): unknown => ({
77	  results: scenario.steps.map(runStep),
78	});
